class Solution:
    def leafSimilar(self, root1, root2):
        def leaves_iter(node):
            out = []
            stack = [node] if node else []
            while stack:
                n = stack.pop()
                if n is None:
                    continue
                if n.left is None and n.right is None:
                    out.append(n.val)
                    continue
                if n.right:
                    stack.append(n.right)
                if n.left:
                    stack.append(n.left)
            return out
        return leaves_iter(root1) == leaves_iter(root2)

